    - {version: 2.1.0, file: prompts/rsc-reviewer/v2.1.0.md, hash: sha256:S2, created: 2026-05-13T00:00:00Z, eval_pass_rate: 0.92, regression_from_prior: 0, status: active}
' > prompts/registry.yaml && bash "$CLAUDE_PLUGIN_ROOT/commands/prompt-rollback.sh" rsc-reviewer && grep -E "2\.0\.0.*status: active" prompts/registry.yaml 1>&2 && grep -E "2\.1\.0.*status: archived" prompts/registry.yaml 1>&2 && echo ok 1>&2
